(() => {
    type CuArray = (CuArray | Date | number | string)[];
    return {build: () => createValidate<CuArray>(), buildErrors: () => noErrs(createGetValidationErrors<CuArray>())};
  })()

c(z.lazy(() => {
    const schema: z.ZodType = z.array(z.union([z.date(), z.number().finite(), z.string(), z.lazy(() => schema)]));
    return schema;
  }))

c(
    Type.Recursive((This) => Type.Array(Type.Union([Type.Date(), Type.Number(), Type.String(), This])))
  )
